VALUES
  ('heelevel3-29a002de-moex-00141', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲經營出租冷凍設備，乙在民國（下同）106年3月1日向甲承租設備一套，為期1個月，租金 新臺幣（下同）10萬元，約定租賃期間屆滿時支付之，租賃期間屆滿，乙未支付租金。乙於107 年8月17日自動償還5000元給甲，之後則避不見面。甲乃憤而決定於109年8月16日提起訴 訟，然當日適逢強颱來襲，交通斷絕，全臺公家機關停止辦公3日，甲忙於處理災害事宜，遲至 109年8月19日提起訴訟請求。下列敘述，何者正確？', '["甲對乙之租金請求權，因5年不行使而消滅", "甲對乙之租金請求權之消滅時效，應自106年3月31日起算", "甲對乙之租金請求權之時效，於乙在107年8月17日承認後，因甲在6個月內未起訴，視為 未中斷", "甲對乙之租金請求權之消滅時效因事變而不完成，至109年9月19日始完成之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00142', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲向乙借一輛自行車，甲騎乘該自行車時遇見丙，丙甚喜歡該輛自行車，甲事前未經乙同意，即 以甲自己之名義出售該輛自行車於不知情之丙，並移轉該輛自行車所有權於丙。關於買賣之債權 行為與移轉所有權之物權行為，下列敘述，何者正確？', '["債權行為有效，物權行為效力未定", "債權行為效力未定，物權行為有效", "債權行為效力未定，物權行為效力未定", "債權行為及物權行為均有效，但乙得撤銷兩項法律行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00143', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲以新臺幣（下同）20萬元向乙購買Ａ錶，乙請求甲先付定金，甲同意，並給付2萬元於乙。下 列敘述，何者正確？', '["2萬元定金為要物契約", "2萬元定金為諾成契約", "2萬元定金為繼續性契約", "契約因不可歸責於雙方當事人之事由，致不能履行時，2萬元定金不得請求返還"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00144', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於買回之敘述，何者正確？', '["買回之期限不得超過5年，超過5年者，買回之約定無效", "買回之價金，當事人得以特約定之", "買回之費用，原則上由買受人與買回人共同負擔", "買受人因可歸責於自己之事由，致不能交付標的物時，買回之約定失效 32620、33320"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00145', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲與乙約定，乙為甲服勞務自110年1月1日起1年，而甲給付報酬。下列敘述，何者錯誤？', '["若甲受領勞務遲延，乙無補服勞務之義務，仍得請求報酬", "甲非經乙同意，不得將其勞務請求權讓與第三人", "乙非經甲同意，不得使第三人代服勞務", "乙得隨時終止契約，但有利於甲之習慣者，從其習慣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00146', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於合夥人責任之敘述，何者正確？', '["民法第681條規定，合夥人對於合夥債務，連帶負其責任，故債權人得選擇先向合夥人個人單 獨所有之財產求償。若有不足之額，再向合夥財產求償", "民法第681條，就合夥人就合夥對外所負之責任，採取併存主義", "依民法規定合夥債務，原則上為各合夥人之公同共有債務", "民法第681條所稱之連帶，係指合夥人與合夥財產之連帶關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00147', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於承攬法定抵押權之敘述，何者錯誤？', '["法定抵押權之設定，係為擔保承攬關係報酬額", "承攬契約以書面定之者，關於法定抵押權之登記，承攬人得單獨申請之", "法定抵押權之標的，限於工作所附定作人所有之不動產", "承攬人得於工作開始前，請求預為抵押權登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00148', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲有一宗A地，為二重買賣，先與乙訂立買賣契約，並將A地交付於乙；後與丙訂立買賣契約， 並將A地之所有權移轉登記於丙。關於甲、乙、丙三人間之法律關係，下列敘述，何者正確？', '["丙得請求乙返還A地之占有", "甲得請求乙返還A地之占有", "乙得請求丙移轉A地所有權", "甲得請求丙返還A地所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00149', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲、乙二人向丙、丁二人承租基地建築二層樓A屋，甲、乙分別共有A屋，丙、丁分別共有A屋 座落之基地。下列共有物，何者並非因物之使用目的而不能分割？', '["A屋座落之基地", "A屋之太平梯", "A屋之亭子腳", "A屋之共有車道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00150', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-111-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列何者，非為不動產物權依法律行為而得喪變更時之要件？', '["物權變動之合意", "書面", "交付", "登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:39+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": "e3d1439f8579", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "326", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
